```cpp
#include <vector>
#include <map>
#include <queue>
#include <algorithm>

using namespace std;

class DSU {
    vector<int> parent;
    vector<int> rank;
public:
    DSU(int size) {
        parent.resize(size + 1);
        rank.resize(size + 1);
        for (int i = 0; i <= size; ++i) {
            parent[i] = i;
            rank[i] = 1;
        }
    }
    int find(int x) {
        if (parent[x] != x) {
            parent[x] = find(parent[x]);
        }
        return parent[x];
    }
    void union(int x, int y) {
        int x_root = find(x);
        int y_root = find(y);
        if (x_root == y_root) return;
        if (rank[x_root] < rank[y_root]) {
            parent[x_root] = y_root;
        } else {
            parent[y_root] = x_root;
            if (rank[x_root] == rank[y_root]) {
                rank[x_root]++;
            }
        }
    }
};

vector<long long> solve(long long c, vector<vector<long long>> connections, vector<vector<long long>> queries) {
    DSU dsu(c);
    for (auto& conn : connections) {
        long long u = conn[0];
        long long v = conn[1];
        dsu.union(u, v);
    }

    map<int, priority_queue<int, vector<int>, greater<int>>> component_heaps;
    for (int i = 1; i <= c; ++i) {
        int root = dsu.find(i);
        component_heaps[root].push(i);
    }

    vector<bool> online(c + 1, true);
    vector<long long> result;

    for (auto& query : queries) {
        if (query[0] == 1) {
            long long x = query[1];
            if (online[x]) {
                result.push_back(x);
            } else {
                int root = dsu.find(x);
                while (!component_heaps[root].empty()) {
                    int top = component_heaps[root].top();
                    if (online[top]) {
                        result.push_back(top);
                        break;
                    } else {
                        component_heaps[root].pop();
                    }
                }
                if (component_heaps[root].empty()) {
                    result.push_back(-1);
                }
            }
        } else {
            long long x = query[1];
            online[x] = false;
        }
    }

    return result;
}
