#include <vector>
#include <map>
#include <priority_queue>
#include <algorithm>

using namespace std;

vector<long long> solve(long long c, vector<vector<long long>> connections, vector<vector<long long>> queries) {
    struct DSU {
        vector<long long> parent;
        vector<long long> rank;
        DSU(long long size) {
            parent.resize(size + 1);
            rank.resize(size + 1);
            for (long long i = 1; i <= size; ++i) {
                parent[i] = i;
                rank[i] = 1;
            }
        }
        long long find(long long x) {
            if (parent[x] != x) {
                parent[x] = find(parent[x]);
            }
            return parent[x];
        }
        void union_(long long x, long long y) {
            long long x_root = find(x);
            long long y_root = find(y);
            if (x_root == y_root) return;
            if (rank[x_root] < rank[y_root]) {
                parent[x_root] = y_root;
            } else {
                parent[y_root] = x_root;
                if (rank[x_root] == rank[y_root]) {
                    rank[x_root]++;
                }
            }
        }
    };

    DSU dsu(c);
    for (auto& conn : connections) {
        long long u = conn[0];
        long long v = conn[1];
        dsu.union_(u, v);
    }

    map<long long, priority_queue<long long, vector<long long>, greater<long long>>> component_heaps;
    vector<bool> online(c + 1, true);

    for (long long i = 1; i <= c; ++i) {
        long long root = dsu.find(i);
        component_heaps[root].push(i);
    }

    vector<long long> result;
    for (auto& query : queries) {
        long long type = query[0];
        long long x = query[1];
        if (type == 1) {
            if (online[x]) {
                result.push_back(x);
            } else {
                long long root = dsu.find(x);
                while (!component_heaps[root].empty()) {
                    long long current = component_heaps[root].top();
                    if (online[current]) {
                        result.push_back(current);
                        break;
                    } else {
                        component_heaps[root].pop();
                    }
                }
                if (component_heaps[root].empty()) {
                    result.push_back(-1);
                }
            }
        } else {
            online[x] = false;
        }
    }

    return result;
}
